// Normalize the binary property name so Extract from File always finds it
const item = $input.first();
const binaryKeys = Object.keys(item.binary || {});

if (binaryKeys.length === 0) {
  throw new Error('No file was uploaded! Please upload a PDF file.');
}

const firstBinaryKey = binaryKeys[0];

return [{
  json: item.json,
  binary: {
    data: item.binary[firstBinaryKey]
  }
}];

const response = $input.first().json;

if (response.error) {
  throw new Error('OpenAI API Error: ' + JSON.stringify(response.error));
}

const analysis = response.choices?.[0]?.message?.content || 'Error: Could not generate analysis.';
const tokensUsed = response.usage?.total_tokens || 'N/A';
const model = response.model || 'gpt-4o-mini';

const promptData = $('Prepare Analysis Prompt').first().json;

const emailBody = `Hello,

Your AI CV Analyzer has completed the analysis.

Candidate: ${promptData.candidateName}
Position: ${promptData.jobPosition}

${analysis}

---
Powered by OpenAI ${model} | Automated with n8n
Tokens used: ${tokensUsed}

Note: This is an AI-generated analysis. Use it as a supplementary tool, not as the sole basis for hiring decisions.`;

return [{
  json: {
    emailBody,
    recipientEmail: promptData.recipientEmail,
    candidateName: promptData.candidateName,
    jobPosition: promptData.jobPosition,
    subject: 'CV Analysis Report: ' + promptData.candidateName + ' - ' + promptData.jobPosition
  }
}];
